import android.content.Intent
import android.net.Uri
import androidx.appcompat.app.AppCompatActivity
import android.os.Bundle
import com.example.myapp.*

class MainActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)
        
        handleUri()
    }
    
    private fun handleUri() {
        val uri: Uri? = intent?.data
        if (uri != null && uri.toString().startsWith("myapp")) {
            when (uri.getPathSegment(1)) {
                "profile" -> startActivity(Intent(this, ProfileActivity::class.java).apply {
                    putExtra("userId", uri.getPathSegment(2))
                })
                "payment" -> when (uri.getPathSegment(2)) {
                    "confirm" -> startActivity(Intent(this, PaymentConfirmationActivity::class.java))
                }
            }
        }
    }
}